import sqlite3
from typing import Optional, Dict, Any

def get_order(user_id: int, order_id: int, db_path: str = 'database.db') -> Optional[Dict[str, Any]]:
    """
    Retrieves order information from the database with proper authorization checks.
    
    Args:
        user_id: The authenticated user's ID (from session/token, NOT from client input)
        order_id: The order ID to retrieve
        db_path: Path to the SQLite database
    
    Returns:
        Dictionary containing order data if authorized, None otherwise
    """
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    cursor = conn.cursor()
    
    try:
        # SECURE: Query filters by BOTH order_id AND user_id to enforce ownership
        # This prevents users from accessing orders that don't belong to them
        query = """
            SELECT order_id, user_id, order_date, total_amount, status, items
            FROM orders 
            WHERE order_id = ? AND user_id = ?
        """
        
        cursor.execute(query, (order_id, user_id))
        row = cursor.fetchone()
        
        if row is None:
            return None
        
        # Convert row to dictionary
        order_data = dict(row)
        
        return order_data
        
    finally:
        conn.close()